"""
MKT Context Commentary — Genesis chapters 31–32
Run: python3 scripts/zc-context-genesis-31-32.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/translation/glossary-hebrew.json (key terms: tĕrāpîm, paḥaḏ, niddāh, gîd hanāšeh)

Key decisions:
- Ch31 v19: teraphim treated as household gods with possible ANE inheritance-rights function (Nuzi parallels)
- Ch31 v35: Rachel's menstrual claim interpreted through ANE purity customs (pre-Levitical form)
- Ch31 v42: "Awe of Isaac" (paḥaḏ yiṣḥāq) treated as a contextual divine title, not a separate deity
- Ch31 v47: Jegar Sahadutha vs. Galeed treated as deliberate bilingual naming marking cultural boundary
- Ch31 v53: Laban's "God of Abraham and Nahor" distinguished from Jacob's monotheistic "Awe of Isaac"
- Ch32 v24: the wrestling figure identified as divine (angel/theophany) per Hosea 12:4 and v30 context
- Ch32 v32: sciatic nerve prohibition treated as an ancient etiological dietary practice
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "31": {
    "1": """<p>"Jacob has taken everything our father owned and has gained all this wealth from what belonged to our father." Laban's sons' grievance is an inheritance complaint: in ANE patriarchal custom, a son's inheritance was the primary social guarantee of his future; watching a son-in-law accumulate wealth from the father's flocks directly threatened the sons' expected share. The complaint is not irrational — Jacob's success (ch30: the streaked/speckled breeding strategy) genuinely redirected wealth from Laban's household to Jacob's. The sons voice what Laban has also begun to feel (v2: his changed countenance), setting up the family crisis that forces the departure.</p>""",
    "2": """<p>"Jacob noticed that Laban's attitude toward him was not what it had been." "Attitude" translates the Hebrew <em>pānāyw</em> (his face/countenance) — the idiom for interpersonal disposition. "His face was not toward him as before (<em>kĕtĕmôl šilšōm</em>)" — the phrase "as yesterday and the day before" is the standard Hebrew idiom for one's habitual/prior state. The changed face is a social signal: patronage has been withdrawn; Jacob is no longer under Laban's protection. In a society where patron-client relationships governed social security, Laban's changed countenance means Jacob's safety in Paddan-Aram is no longer guaranteed.</p>""",
    "3": """<p>"Then the LORD said to Jacob, 'Go back to the land of your fathers and to your relatives, and I will be with you.'" The divine command to return mirrors the original command to Abraham to depart Haran (12:1). The promise "I will be with you (<em>ʾehyeh ʿimmāk</em>)" activates the Bethel covenant's unconditional promise (28:15: "I am with you and will watch over you wherever you go, and I will bring you back to this land"). Twenty years later, YHWH remembers and executes the promise. The command to return is both a relief from the hostile Laban situation and the fulfillment of the covenant that sent Jacob to Paddan-Aram in the first place.</p>""",
    "4": """<p>"So Jacob sent word to Rachel and Leah to come out to the fields where his flocks were." The choice of the field rather than the house for the family council is a social precaution: Jacob needs privacy from Laban's ears. The flocks were Jacob's domain — economically his territory within the Laban household — while the house was Laban's domain. Meeting in the field also signals the transition of allegiance Jacob is proposing: he is asking his wives to leave their father's house (<em>bêt ʾāḇ</em>) and join his household as it moves toward Canaan. The <em>bêt ʾāḇ</em> (father's house) was the primary social unit of ANE kinship; leaving it required strong motivation.</p>""",
    "5": """<p>"The God of my father has been with me." Jacob's reframing of the changed situation is theological: Laban's hostility is countered by YHWH's faithfulness. Jacob explicitly contrasts "your father's attitude" (hostile) with "the God of my father" (faithful) — the two competing authorities in Jacob's life. "The God of my father (<em>ʾĕlōhê ʾāḇî</em>)" is the covenant-lineage formula: Abraham's God, who became Isaac's God, is now Jacob's God — each generation in the same covenant-chain. The phrase grounds Jacob's appeal to his wives in the covenant's demonstrated track record, not just Jacob's personal wishes.</p>""",
    "6": """<p>"You know that I've worked for your father with all my strength" — the appeal to labor-testimony is Jacob's covenant-loyalty claim: he did not shortchange Laban; he served faithfully. The phrase "with all my strength (<em>bĕḵol-kōḥî</em>)" is the superlative service formula — the same language used in the Shema ("love the LORD your God with all your strength," Deut 6:5). Jacob's invocation of his full-strength service establishes the moral inequality between his faithful labor and Laban's exploitative wage-changes — the context needed for the daughters to understand why YHWH's redistribution (v9) was just.</p>""",
    "7": """<p>"Your father has cheated me by changing my wages ten times." The "ten times" (<em>ʿăśeret mōnîm</em>) is likely a round number for "many times" — "ten" in ANE idiom often means "repeatedly/frequently" (cf. Num 14:22: "ten times they tested me"). The wage-changes were Laban's attempts to limit Jacob's accumulating wealth: changing the agreement each time Jacob's strategy succeeded. The word "cheated" (<em>hēlal</em>, to exchange/change fraudulently) characterizes Laban's repeated wage-revisions as contract violations. ANE labor agreements, when witnessed and sworn, were legally binding; Laban's unilateral changes were violations of covenant-contract.</p>""",
    "8": """<p>"If he said, 'The speckled ones will be your wages,' then all the flocks gave birth to speckled young." Jacob explains the breeding-outcome pattern as divine provision: whatever Laban stipulated as Jacob's wages, God arranged for the flocks to produce that type. The narrative retroactively reframes the ch30 breeding strategy (visual conditioning with striped rods) as the form through which divine provision operated, not as Jacob's cleverness alone. The theological point: YHWH overruled Laban's self-protective wage-changes by superintending the reproductive outcomes — Laban's manipulations were futile against the covenant-protection.</p>""",
    "9": """<p>"So God has taken away your father's livestock and has given them to me." Jacob's theological claim about the wealth-transfer sets the stage for the wives' response (v16). The statement "God has taken away (<em>wayyaṣṣēl ʾĕlōhîm</em>, God snatched/rescued)" uses the same verb as the deliverance from Egypt (Exod 3:8: "I have come down to rescue them") — God's active intervention to transfer resources from oppressor to covenant-heir. In ANE context, this claim would sound scandalous: property transfers required witnesses and legal process. Jacob's claim that God effected the transfer directly makes YHWH the legal agent of what Laban experienced as theft.</p>""",
    "10": """<p>"In breeding season I once had a dream in which I looked up and saw that the male goats mating with the flock were streaked, speckled or spotted." The dream-vision as a form of divine communication was the standard ANE mechanism for receiving messages from the gods (cf. Pharaoh's dreams, ch41; Abimelech's dream, ch20; Laban's dream, v24). Jacob's dream of the streaked male goats retroactively provides divine confirmation for the breeding strategy of ch30 — the visual conditioning with the rods was not Jacob's invention but a divinely directed method. The breeding season (<em>hayyōṣĕʾôt</em>, the time of the flock's going out to mate) specifies when the dream occurred — grounding it in the agricultural/pastoral calendar.</p>""",
    "11": """<p>"The angel of God said to me in the dream, 'Jacob.' I answered, 'Yes.'" The angel of God (<em>malʾak hāʾĕlōhîm</em>) in the dream uses the same divine-messenger formula as the Bethel vision (28:12) and Hagar's encounters (16:7; 21:17). The double-name call and the <em>hinnēnî</em> (Yes/Here I am) response is the theophanic urgency formula (also 22:1,11; 46:2). The angel's appearance in a dream rather than direct waking vision is the standard form for communicating with those not at a covenant-site — Jacob is in Paddan-Aram, not at Bethel or Mamre.</p>""",
    "12": """<p>"I have seen all that Laban has been doing to you." The divine surveillance declaration — "I have seen (<em>rāʾîtî</em>)" — is the covenant-protection formula: YHWH has observed the injustice and is now acting on it. The same verb appears in Exod 3:7 ("I have indeed seen the misery of my people in Egypt") — the pattern of divine seeing-then-delivering runs from the patriarchal stories into the Exodus. Laban's repeated injustices are not unknown to the divine watcher; the breeding-dream is the visible consequence of YHWH's surveillance-turned-action on Jacob's behalf.</p>""",
    "13": """<p>"I am the God of Bethel, where you anointed a pillar and where you made a vow to me." The angel self-identifies with the Bethel theophany (28:10-22) — the specific covenant-event that established Jacob's relationship with YHWH. This is the first divine appearance since Bethel, 20 years later. The reference to "the pillar you anointed" and "the vow you made" invokes Jacob's conditional vow (28:20-22: "if God will be with me and watch over me... then the LORD will be my God"). The divine self-identification as "the God of Bethel" is YHWH saying: "I remember your vow; your conditions have been met; now fulfill your commitment to return."</p>""",
    "14": """<p>"Do we still have any share in the inheritance of our father's estate?" Rachel and Leah's response opens with an inheritance question. In ANE law, daughters typically did not inherit from their father (inheritance passed through male lines), but their bride-price (<em>môhar</em>) was supposed to form a security fund for the daughters. The question "do we have any share in our father's house?" is rhetorical — they know the answer is no. The question frames their alignment with Jacob: if Laban has effectively cut them off from inheritance, they have nothing to lose by leaving and everything to gain by following the husband who has prospered under YHWH's blessing.</p>""",
    "15": """<p>"Does he not regard us as foreigners? Not only has he sold us, but he has used up what was paid for us." The daughters indict Laban on two counts: (1) he treated them as foreigners (<em>nākrîyyôt</em>, alien women, not proper family members) rather than daughters, and (2) he consumed the bride-price that should have been preserved as a security fund for them. In ANE custom, the <em>môhar</em> (bride-price) paid for a wife was held in trust for the wife's use in case of divorce or widowhood; if Laban spent it on himself, he violated his daughters' economic rights. Their grievance is legally substantive — and explains why YHWH's transfer of wealth to Jacob was, from the daughters' perspective, justice rather than theft.</p>""",
    "16": """<p>"Surely all the wealth that God took away from our father belongs to us and our children. So do whatever God has told you." Rachel and Leah's conclusion is theologically and economically decisive: they claim the transferred wealth as their own (via their defrauded inheritance rights) and endorse Jacob's divine commission. The phrase "do whatever God has told you (<em>kōl ʾăšer ʾāmar ʾĕlōhîm ʾēlêkā ʿăśēh</em>)" is full covenant-obedience language — they submit to YHWH's directive as transmitted through Jacob. This is the moment the nuclear family unit (Jacob + wives + children) definitively aligns against the extended family (Laban's household) in the covenant-journey.</p>""",
    "17": """<p>"Then Jacob put his children and his wives on camels." The camels as transport for the family echoes the camel-caravan that brought Rebekah to Isaac (ch24). Camels were expensive luxury animals used for long-distance travel; their use signals that Jacob's wealth is now substantial enough to equip a large family for a significant journey. The order of listing — children first, then wives — follows the narrative's emphasis on the covenant-family's generational continuity: the children are the covenant-heirs whose safe delivery to Canaan is the journey's purpose.</p>""",
    "18": """<p>"He drove all his livestock ahead of him, along with all the goods he had accumulated in Paddan Aram." The accumulation of twenty years is being mobilized into a covenant-family migration: livestock (the primary wealth), goods (<em>rĕkûšô</em>, movable property — the same word used for Abram's goods when he left Egypt, 13:6), all moving toward Canaan. "Paddan Aram" — the plain of Aram, the region around Harran — is now the place being left, not the destination. The geographic reversal (going to Paddan-Aram: ch28-30; leaving Paddan-Aram: ch31-32) is the covenant-journey's second arc returning to its origin.</p>""",
    "19": """<p>"Rachel stole her father's household gods." The <em>tĕrāpîm</em> (household gods) were small figurines used for divination and possibly household ritual. The function of the <em>tĕrāpîm</em> in the ANE has been illuminated by the Nuzi legal texts (15th-century BCE Hurrian documents from northern Mesopotamia): in some Hurrian legal customs, possession of the household gods was associated with inheritance rights — specifically, a son-in-law who possessed his father-in-law's household gods could claim the paternal estate. If Rachel stole them to assert an inheritance claim or to prevent Laban from using them for divination to locate and reclaim Jacob's family, both motivations have ancient-legal grounding. The <em>tĕrāpîm</em> will later be condemned as divination objects (1 Sam 15:23; 2 Kgs 23:24; Zech 10:2).</p>""",
    "20": """<p>"Jacob deceived Laban the Aramean by not telling him he was running away." The verb "deceived" renders <em>wayyignōb ʾet-lēḇaḇ lāḇān</em> — literally "he stole Laban's heart." The idiom "to steal someone's heart" in Hebrew means to deceive their mind — to act without their awareness or against their intention. Jacob's deception of Laban by secret departure mirrors his earlier deceptions (of Esau in ch25-27). However, the narrative context places this deception in a different moral register: he is fleeing exploitation with YHWH's explicit commission (v3), not scheming for personal advantage. The "Aramean" designation for Laban — used three times in this chapter (vv20,24; cf. 25:20) — marks the cultural-ethnic boundary Jacob is crossing.</p>""",
    "21": """<p>"He crossed the Euphrates River, and headed for the hill country of Gilead." The Euphrates crossing is a geopolitical boundary: the Euphrates (<em>hannāhār</em>, the River, as Mesopotamians called it) was the western limit of Mesopotamian civilization and the eastern limit of Canaan's sphere. Crossing it was a point of no return — once across, Jacob was out of Laban's easy reach. The Gilead hill country (modern northwestern Jordan) was the first significant highland feature of the Transjordanian return route. Gilead will later be a significant Israelite territory (Num 32; the tribes of Reuben and Gad settled there), but at this point it is unclaimed pastorland east of the Jordan.</p>""",
    "22": """<p>"On the third day Laban was told that Jacob had fled." The three-day delay before Laban learned of Jacob's departure was built into Jacob's strategy: he left without warning (<em>wayyibrāḥ hûʾ</em>, he fled) and the distance covered in three days would have placed him well across the Euphrates. In ANE terms, three days was approximately 60-90 miles at caravan pace. By the time Laban organized a pursuit (v23: "with his relatives"), Jacob had a substantial head start. The three-day delay is also narratively significant: three days appears repeatedly in Genesis at pivotal moments (22:4 — Abraham sees Moriah on the third day; 40:13,20 — three-day prison delay before cup-bearer's release).</p>""",
    "23": """<p>"Taking his relatives with him, he pursued Jacob for seven days and caught up with him in the hill country of Gilead." The seven-day pursuit covers approximately 300-400 miles — an aggressive pursuit requiring the mobilization of Laban's household clan. Laban's "relatives" (<em>ʾeḥāyw</em>, his brothers/kinsmen) constitute his military/social support structure — a family militia. The hill country of Gilead, east of the Jordan, was roughly 400-450 miles from Harran, at the outer edge of a seven-day rapid pursuit. The catch-up in Gilead sets the confrontation at the geographic midpoint between Paddan-Aram (where Laban has authority) and Canaan (where YHWH's covenant operates) — neutral territory for the treaty that will follow.</p>""",
    "24": """<p>"God came to Laban the Aramean in a dream at night." The divine warning to Laban in a dream is parallel to YHWH's warning to Abimelech (20:3) — God communicates with non-covenant figures through dreams to protect the covenant-bearer. Laban receives a direct divine communication, making him aware of YHWH's involvement. The prohibition "be careful not to say anything to Jacob, either good or bad (<em>mikkōl-ṭôḇ ʿaḏ-rāʿ</em>)" is the Hebrew idiom for absolute prohibition of interference — he may not speak anything that would alter the outcome in any direction. YHWH has set the terms of the encounter before it happens; Laban's superior force is restrained by divine decree.</p>""",
    "25": """<p>"Laban caught up with Jacob, who had set up his tent in the hill country of Gilead, and Laban and his relatives camped there too." The two camps in Gilead are the visual drama: Laban's larger force (with "his relatives," v23) and Jacob's family-with-flocks. The tent-setting in the hills creates the stage for Laban's confrontation. In ANE military convention, a pursuer who camps near a fleeing group without immediately attacking is observing a diplomatic protocol — giving notice of his presence before formal confrontation. Laban's camping rather than attacking confirms he is following the divine restraint of v24, but also that he intends a face-to-face reckoning.</p>""",
    "26": """<p>"You've deceived me, and you've carried off my daughters like captives in war." Laban's charge uses two metaphors: (1) deception (<em>wattiḇraḥ beśtēr</em>, you fled in secret/by stealth) and (2) military capture (<em>kišĕḇûyôt ḥāreḇ</em>, like captives of the sword). The war-captive metaphor is the most serious rhetorical charge: daughters taken in war are enslaved and dishonored; Laban characterizes Jacob's departure as an act of violence against his family. The charge is legally significant: in ANE family law, a man who took his wife away from her father's household without consent could be accused of abduction. Jacob's defense (v31) will address the fear behind the secret departure.</p>""",
    "27": """<p>"Why didn't you tell me, so I could send you away with joy and singing to the music of timbrels and harps?" Laban's appeal to the missed farewell ceremony identifies the social injury. In ANE culture, the departure of a daughter from her father's household was accompanied by a formal farewell ceremony: singing, music (timbrels and harps — <em>tōp wĕḵinnôr</em>), and a public blessing from the father. The ceremony was both a social celebration and a public acknowledgment of the daughter's transition from one household to another. By leaving secretly, Jacob deprived Laban of this social ritual — and deprived the daughters of their proper farewell. Laban's complaint is partly self-interested but also socially legitimate: the departure violated established custom.</p>""",
    "28": """<p>"You didn't even let me kiss my grandchildren and my daughters goodbye." The grandfather's kiss of farewell to grandchildren was a formal act of blessing and farewell in ANE family culture. The grandchildren — Jacob's eleven sons at this point — were Laban's legitimate grandchildren whose departure represented a permanent loss. Laban's grief here is genuine even amid his self-interest: the departure of his daughters and grandchildren to Canaan, hundreds of miles away, was effectively a permanent separation in a world without rapid communication. "You have done a foolish thing (<em>yēš-lĕʾēl yāḏî</em>)" — literally "it is in the power of my hand" — is Laban asserting his ability to retaliate, not calling Jacob stupid.</p>""",
    "29": """<p>"I have the power to harm you; but last night the God of your father said to me, 'Be careful not to say anything to Jacob, either good or bad.'" Laban's frank admission of his military superiority ("it is in the power of my hand to harm you") followed immediately by the divine restraint creates the chapter's theological irony: the stronger man is held back by the God of the weaker man. Laban's acknowledgment of the divine warning to a third party (Jacob and his witnesses) is the pagan uncle's involuntary testimony to YHWH's authority. He cannot harm Jacob not because he lacks the power but because God has constrained him — the same pattern as Abimelech's restrained hand (20:6).</p>""",
    "30": """<p>"But why did you steal my gods?" The question about the <em>tĕrāpîm</em> shifts the confrontation from the departure's legality to the theft's reality. Laban's "my gods (<em>ʾĕlōhāy</em>)" — possessive, personal gods — reveals his attachment to the household figurines. If the <em>tĕrāpîm</em> carried legal inheritance significance (Nuzi parallel), their theft was not merely a religious offense but an economic one — potentially a claim on Laban's estate. The question also creates narrative irony: Laban is looking for his gods while speaking to a man protected by the God who has already overruled Laban's entire plan.</p>""",
    "31": """<p>"I was afraid, because I thought you would take your daughters away from me by force." Jacob's answer to Laban's first charge (secret departure) is honest: fear drove the secrecy. The fear was rational — Laban's power over his daughters was legally substantial; he could legally prevent Jacob from taking them if he chose to contest it in front of witnesses. Jacob's departure without notice was a self-protective strategy against a patron who had already changed his wages ten times and whose sons were openly hostile. The fear-based answer is more sympathetic than the earlier deceptions; Jacob is no longer scheming for advantage but fleeing exploitation.</p>""",
    "32": """<p>"But if you find anyone who has your gods, that person shall not live." Jacob's oath is unwitting: he does not know Rachel has the <em>tĕrāpîm</em>. The conditional death-curse he pronounces over the thief creates a narrative tension resolved not by discovery but by Rachel's stratagem (vv33-35). "In the presence of our relatives (<em>negeḏ ʾaḥênû</em>)" — witnesses are invoked: the search is conducted publicly, with both family clans present. The witness-presence transforms the search into a formal legal proceeding — a witnessed search whose negative result would clear Jacob's household officially.</p>""",
    "33": """<p>"So Laban went into Jacob's tent and into Leah's tent and into the tent of the two female servants, but he found nothing." The search order — Jacob, Leah, two female servants — moves from the head of household to the secondary wives, saving Rachel for last. Laban is conducting a systematic search. The tents are separate domestic units for each wife, reflecting the polygamous household structure where each wife had her own living space within the larger camp. The thoroughness of the search (every tent searched) establishes the credibility of the eventual failure to find the gods — not negligent searching but comprehensive investigation foiled by Rachel's stratagem.</p>""",
    "34": """<p>"Now Rachel had taken the household gods and put them inside her camel's saddle and was sitting on them." The camel saddle (<em>kar-haggāmāl</em>, camel cushion/saddle-bag) was a large padded riding-seat for long-distance camel travel — large enough to conceal small figurines. Rachel's placement of the <em>tĕrāpîm</em> under her saddle, with herself sitting on it, is a layered concealment strategy. The physical concealment is effective; the impurity strategy (v35) makes the concealment approach untouchable. Laban "searched through everything in the tent but found nothing" — the thoroughness of the failed search vindicates Jacob's oath while preserving Rachel's concealment.</p>""",
    "35": """<p>"I'm having my period (<em>derek nāšîm lî</em>, the way of women is upon me). So he searched but could not find the household gods." Rachel's appeal to her menstrual condition (<em>niddāh</em>, the period of ritual impurity) exploits ANE purity customs. Under both pre-Mosaic custom and later Levitical law (Lev 15:19-24), a menstruating woman transmitted ritual impurity to anything she sat upon. Anyone who touched the surface she sat on became ritually impure for the remainder of the day. Whether Laban observed this custom strictly enough to avoid touching the saddle, or whether he simply did not think to look under the cushion on which Rachel sat, the stratagem succeeds. Rachel's bold use of bodily reality to protect stolen religious objects creates one of the narrative's most ironic moments.</p>""",
    "36": """<p>"Jacob was angry and took Laban to task. 'What is my crime? How have I wronged you that you hunt me down?'" Jacob's anger (<em>wayyiḥar lĕyaʿăqōḇ</em>, Jacob's anger burned) is the narrative's first instance of Jacob expressing righteous indignation — previously his anger was never recorded, only his strategies. The vindication by the failed search releases twenty years of accumulated grievance. "Hunt me down (<em>wattiddaleq ʾaḥărāy</em>, you pursued hotly after me)" uses the hunting-pursuit vocabulary — Laban has treated Jacob like prey rather than family. Jacob's subsequent speech (vv37-42) is the most sustained self-defense in Genesis, a rhetorical inventory of faithful service versus exploitative treatment.</p>""",
    "37": """<p>"Now that you have searched through all my goods, what have you found that belongs to your household? Put it here in front of your relatives and mine, and let them judge between the two of us." Jacob demands a public adjudication — both families' witnesses as judges. This is the ANE equivalent of a legal tribunal: lay the evidence before the assembled witnesses and let them render judgment. Jacob's confidence in the public verdict (the search found nothing) allows him to shift from defense to prosecution: having been found innocent of theft, he now indicts Laban for twenty years of wage-fraud and exploitation.</p>""",
    "38": """<p>"I have been with you for twenty years now. Your sheep and goats have not miscarried, nor have I eaten rams from your flocks." Jacob's accounting specifies the quality of his shepherding service. The absence of miscarriages (<em>lōʾ-šikkēlû</em>, have not dropped young prematurely) in twenty years of a large flock is remarkable; miscarriages were normal pastoral losses. Jacob's pastoral care prevented them. "Nor have I eaten rams from your flocks" — the shepherd's right to consume animals that died naturally was common (Lev 22:8; Ezek 44:31), but Jacob claims he abstained even from this perquisite, eating none of Laban's animals.</p>""",
    "39": """<p>"I did not bring you animals torn by wild beasts; I bore the loss myself." Under ANE shepherding law (Code of Hammurabi §266), a shepherd was not liable for animals killed by wild beasts if he could prove it — he brought the evidence of the attack and was released from liability. Jacob claims to have gone beyond legal obligation: instead of presenting evidence of beast-attacks to avoid liability, he personally paid for every animal killed — absorbing losses he was not legally required to cover. "You held me responsible for whatever was stolen by day or night" — the combination of beast-attack losses and theft claims imposed on Jacob doubled the standard pastoral risk.</p>""",
    "40": """<p>"The heat consumed me in the daytime and the cold at night, and sleep fled from my eyes." The physical conditions of ancient shepherding in the Levant are accurately described: summer daytime temperatures in the Near East were extreme; nighttime temperatures in the hill country dropped sharply. Sleep deprivation — maintaining vigilance against predators and thieves through both day and night — was the shepherd's constant burden. Jacob's physical description personalizes the labor account: this is not an abstract complaint but a visceral record of the bodily cost of twenty years of faithful service in a harsh environment.</p>""",
    "41": """<p>"I worked for you fourteen years for your two daughters and six years for your flocks, and you changed my wages ten times." The twenty-year account is detailed: 7 years for Leah (served for Rachel but given Leah instead), 7 more years for Rachel (ch29), then 6 years for the flock-wages agreement (ch30). The wage-changes "ten times" confirms Jacob's earlier claim (v7) — Laban repeatedly revised the breeding-contract to limit Jacob's accumulation. The specific breakdown (14 + 6 = 20) is the only precise account of the sojourn's duration in the narrative, establishing Jacob's claim to an exact time-record of his service.</p>""",
    "42": """<p>"The God of my father, the God of Abraham and the Awe of Isaac (<em>paḥaḏ yiṣḥāq</em>)" — this unusual divine title appears only here and in v53. <em>Paḥaḏ</em> means dread/awe/fear — an attribute of YHWH as experienced by Isaac, possibly connected to the terror of the Akedah (ch22) where Isaac experienced the God who demanded his life. The title may encode Isaac's personal testimony of meeting a God of overwhelming power. "But God has seen my hardship (<em>ʿonyî</em>, my affliction/poverty) and the toil of my hands (<em>yĕgîaʿ kappay</em>)" — YHWH's vision of Jacob's condition is the covenant-surveillance that leads to intervention. "Last night he rebuked you" — Jacob interprets Laban's restrained hand as divine rebuke, not just as Laban's choice.</p>""",
    "43": """<p>"The women are my daughters, the children are my children, and the flocks are my flocks. All you see is mine." Laban's response is a property claim: he asserts ownership over everything in Jacob's camp — daughters, grandchildren, flocks — on the basis of his patriarchal authority. The claim is technically true in ANE social law: daughters and their children were legally subject to the father's household authority, and the flocks were originally Laban's. But the claim rings hollow after the failed search and Jacob's twenty-year labor account. The concession "yet what can I do today?" admits that Laban's legal claims are unenforceable against the combination of YHWH's protection and the witnesses who have heard Jacob's testimony.</p>""",
    "44": """<p>"Come now, let's make a covenant (<em>bĕrît</em>), you and I, and let it serve as a witness between us." The shift from confrontation to treaty-making is the chapter's diplomatic resolution. The covenant proposal is Laban's face-saving retreat: having failed to find the gods and having heard Jacob's righteous indignation, Laban proposes a formal boundary-agreement. ANE boundary treaties required physical markers, oath-taking, and divine witnesses — all of which follow in vv45-54. The covenant is not a statement of friendship or trust between equals but a formal limitation of hostility: each side commits to not crossing the boundary to harm the other.</p>""",
    "45": """<p>"So Jacob took a stone and set it up as a pillar (<em>maṣṣēḇāh</em>)." The single standing-stone pillar (<em>maṣṣēḇāh</em>) is Jacob's standard covenant-marker: he set up a pillar at Bethel (28:18), and he will set one up at Rachel's grave (35:20) and on Ephrath's hill (35:14). The pillar is the individual covenant-witness monument. The subsequent heap of stones (v46) adds a communal element: both families contribute stones to the covenant-boundary marker. The combination of single pillar (Jacob's act) plus communal heap (family witnesses' act) creates a dual-witness monument for the Laban-Jacob boundary treaty.</p>""",
    "46": """<p>"Gather some stones. So they took stones and piled them in a heap (<em>gal</em>), and they ate there by the heap." The stone heap as boundary-marker is an ANE custom: communal construction of a cairn witnessed by both parties created a permanent, publicly known boundary. The meal "by the heap" is the covenant-ratification meal — shared eating seals ANE treaties by creating a communal bond between the parties (cf. the Sinai covenant meal, Exod 24:11; Isaac's covenant with Abimelech, 26:30). The meal before the formal oath (vv48-53) follows the standard ANE treaty sequence: shared meal establishes the relationship context within which the oath will operate.</p>""",
    "47": """<p>"Laban called it Jegar Sahadutha, and Jacob called it Galeed." The bilingual naming is historically significant: Jegar Sahadutha is Aramaic (the language of Laban's cultural sphere, the northern Mesopotamian Aramean world), while Galeed is Hebrew (the Canaanite language family of Jacob's covenant-world). Both mean "heap of witness" — the same concept in two languages. The bilingual naming is the treaty's cultural boundary-marker: these two men belong to different language communities, and the boundary they are establishing separates those cultural worlds. The Aramean-speaking world (Laban's side) and the Hebrew-speaking world (Jacob's side, the emerging Israelite identity) diverge at this heap.</p>""",
    "48": """<p>"This heap is a witness between you and me today. That is why it was called Galeed." The <em>gal</em> (heap) of v46 is now formally named Galeed (<em>galʿēḏ</em>, heap of witness — from <em>gal</em>, heap + <em>ʿēḏ</em>, witness). The stone-heap-as-witness is an ANE legal fiction: physical objects could serve as treaty-witnesses, invoked by both parties as proof of the agreement's terms. The "today (<em>hayyôm</em>)" marks the formal date of the treaty — boundary treaties required a specific date-of-establishment for legal validity. The naming formula ("that is why it was called") grounds a known geographic name in the founding narrative — readers who knew Gilead as a place would now know its treaty-origin.</p>""",
    "49": """<p>"It was also called Mizpah, because he said, 'May the LORD keep watch (<em>yiṣep YHWH</em>) between you and me when we are away from each other.'" Mizpah (<em>miṣpāh</em>, watchpost/watchtower — from <em>ṣāpāh</em>, to watch/lookout) is the second name for the site, derived from the mutual-surveillance clause of the treaty. The Mizpah blessing — "may the LORD watch between us" — has been taken out of context in later tradition as a blessing of divine closeness. Its original context is the opposite: it is an absence-clause, a treaty-surveillance agreement for parties who cannot trust each other when apart. YHWH watches because neither party can watch the other across the distance; the divine surveillance is the treaty's enforcement mechanism for the unseen interval.</p>""",
    "50": """<p>"If you mistreat my daughters or if you take any wives besides my daughters, even though no one is with us, remember that God is a witness between you and me." The Mizpah clause addresses Laban's primary concern: his daughters' treatment after the separation. The prohibition against taking additional wives is a marriage-contract clause — Laban is protecting his daughters' status against being displaced by other wives (a real risk in polygamous ANE culture). "Even though no one is with us" acknowledges that the covenant operates in secret as well as public: Jacob cannot act differently when unwatched, because YHWH watches the unwatched spaces. This is one of the earliest explicit statements of divine omnipresence as a moral accountability mechanism.</p>""",
    "51": """<p>"Here is this heap, and here is this pillar I have set up between you and me." Laban's repetition of the boundary markers (heap + pillar) in the formal oath-clause is the legal specification of the treaty terms: the physical objects are the boundary. ANE boundary treaties required precise physical description of the markers — the heap and pillar are the legal monuments that define the boundary's location. The repetition in legal contexts (Laban restating what Jacob established in v45-46) is the treaty's formal ratification language: both parties acknowledge the same markers as the binding boundary.</p>""",
    "52": """<p>"This heap is a witness, and this pillar is a witness, that I will not go past this heap to your side to harm you and that you will not go past this heap and pillar to my side to harm me." The mutual non-aggression clause specifies the treaty's core obligation: neither party crosses the boundary in hostility. The precise directionality — "I will not go past... to your side" and "you will not go past... to my side" — is the standard ANE boundary-treaty bilateral format. Both parties commit symmetrically. The Gilead heap thus becomes the permanent eastern boundary of the covenant-family's territory: Laban and his Aramean world remain on the eastern side; Jacob and his family proceed westward toward Canaan.</p>""",
    "53": """<p>"May the God of Abraham and the God of Nahor, the God of their father, judge between us." Laban invokes the God of Abraham and the God of Nahor as if they might be different deities — the patron-gods of two branches of the Terah family. In polytheistic ANE understanding, different family clans had different patron deities, even within related families. Jacob's response is careful: "Jacob took an oath in the name of the Awe of his father Isaac" — not in the name of Nahor's god. Jacob swears by YHWH alone, declining Laban's formulation of two gods. The distinction is subtle but theologically decisive: Laban invokes two patron-deities; Jacob invokes one covenant God. The covenant-treaty is concluded with both parties invoking their divine witnesses — but only one God is actually present and active.</p>""",
    "54": """<p>"He offered a sacrifice there in the hill country and invited his relatives to a meal." The sacrifice (<em>wayyizbāḥ yaʿăqōḇ zeḇaḥ</em>) at the treaty site is the covenant-sacrifice that accompanies the oath-taking — the standard ANE sacrificial ratification of international treaties. The meal that follows (shared by both families: "his relatives" = members of both groups present) is the covenant-ratification feast. The pattern — sacrifice + shared meal — mirrors the Sinai covenant (Exod 24:5-11: sacrifice, then the elders eat and drink before YHWH). Shared food after shared sacrifice seals the bond and marks the treaty's formal completion. Both families eat together on the boundary that divides them.</p>""",
    "55": """<p>"Early the next morning Laban kissed his grandchildren and his daughters and blessed them. Then he left and returned home." The formal farewell Laban claimed Jacob had denied him (v28) is now enacted the morning after the treaty. The blessing of grandchildren and daughters is the patriarchal benediction that Laban had wanted to perform before the departure — now given at the border, one day late. The departure formula "and he left and returned (<em>wayyēlek wayyāšāḇ</em>) to his place" closes the Laban-narrative permanently: he returns to Paddan-Aram, disappears from the narrative, and is never mentioned again. The treaty boundary holds; Jacob proceeds westward.</p>"""
  },
  "32": {
    "1": """<p>"Jacob also went on his way, and the angels of God met him." The angels of God (<em>malʾakê ʾĕlōhîm</em>) appearing immediately after Laban's departure creates a divine-escort narrative that mirrors the Bethel theophany at Jacob's departure from Canaan (28:12: "angels of God ascending and descending on it"). The covenant-journey began and ends with angelic encounter: Jacob left Canaan with a vision of divine protection; he returns to Canaan with divine escort. The angels here do not speak — their presence is the message. The covenant-bearer approaches the promised land under YHWH's visible protection, not merely his abstract promise.</p>""",
    "2": """<p>"This is the camp of God! So he named that place Mahanaim." Mahanaim (<em>maḥănayim</em>, dual form of <em>maḥăneh</em>, camp) means "two camps" — Jacob's camp and YHWH's camp. The divine military camp alongside Jacob's human camp is the warrior-escort imagery: YHWH's forces accompany the covenant-family into the land. The Mahanaim site will later be the location where David fled Absalom (2 Sam 17:24,27) and where Solomon's administrative district included Mahanaim (1 Kgs 4:14). The name-giving formula grounds a known Transjordanian place-name in Jacob's encounter with the divine army.</p>""",
    "3": """<p>"Jacob sent messengers (<em>malʾākîm</em>) ahead of him to his brother Esau." The word <em>malʾākîm</em> (messengers/angels) is the same word as the divine angels of vv1-2. The verbal echo is deliberate: just as divine messengers escorted Jacob, human messengers go ahead of him. Jacob the supplanter now organizes his return diplomatically, acknowledging the covenant-complication that Esau represents. "The land of Seir, the country of Edom" — Seir/Edom is the Transjordanian/Arabian territory south of the Dead Sea where Esau settled (ch36); at this point in the narrative Esau has moved there permanently, suggesting significant time has passed since his Canaanite marriages (ch26).</p>""",
    "4": """<p>"Your servant Jacob says, I have been staying with Laban and have remained there till now." The "your servant (<em>ʿaḇdĕkā</em>)" formula is the diplomatic self-humbling before a superior — Jacob places himself in the client position before Esau. The message intentionally omits mention of YHWH's blessing or Jacob's wealth accumulation — leading with "I have been staying with Laban" presents Jacob as a returning family member, not a rival. The phrase "remained there till now (<em>wāʾēḥar ʿaḏ-ʿattāh</em>)" acknowledges the long absence without explaining it as flight — diplomatic understatement.</p>""",
    "5": """<p>"I have cattle and donkeys, sheep and goats, male and female servants." The inventory of Jacob's wealth serves two diplomatic functions: (1) it demonstrates that Jacob is not returning to claim Esau's inheritance or blessing — he is independently wealthy; (2) it signals his capacity to give gifts if the meeting goes well. "That I may find favor (<em>ḥēn</em>) in your eyes" — the patron-client favor-seeking formula of the weaker party before the stronger. Jacob's self-presentation as wealthy-but-humble is a calculated diplomatic posture: too poor and Esau might be contemptuous; too proud and Esau might be provoked.</p>""",
    "6": """<p>"Now he is coming to meet you, and four hundred men are with him." The messengers' report transforms Jacob's diplomatic initiative into a military crisis. Four hundred men is a significant fighting force — the same number that rallied around David in distress (1 Sam 22:2) and around Nabal (1 Sam 25:13). Whether Esau is coming as a welcoming party or a war party is ambiguous from the number alone — Jacob assumes the worst (v7: "in great fear and distress"). The report inverts the power dynamic: Jacob sent a message of conciliation; Esau responds with an army.</p>""",
    "7": """<p>"In great fear and distress Jacob divided the people who were with him into two groups." Jacob's military division is the "Mahanaim strategy" — two camps, if one is struck the other escapes (v8). The vocabulary of fear — <em>wayyîrāʾ yaʿăqōḇ mĕʾōḏ wayyēṣer lô</em> (Jacob was very afraid and he was distressed) — uses two fear-words: <em>yārēʾ</em> (to be afraid) and <em>ṣûr</em> (to be pressed/distressed). The doubled fear-vocabulary marks this as the narrative's most intense anxiety. The practical wisdom of the military division shows Jacob operating simultaneously on two tracks: the covenant-faith he will express in prayer (v9-12) and the human strategy he employs in planning.</p>""",
    "8": """<p>"If Esau comes and attacks one group, the group that is left may escape." The two-camp survival strategy mirrors the Mahanaim vision (two camps = Jacob's + God's): the physical two-camp division reflects the spiritual two-camp reality. The strategy is sound ANE military planning: dividing assets reduced total loss risk. The word "escape (<em>lĕpelēṭāh</em>)" is the covenant-remnant vocabulary — the same root as <em>pālaṭ</em> (to escape/deliver) used throughout the prophets for Israel's surviving remnant. Jacob's practical military calculation uses the language of covenant-survival.</p>""",
    "9": """<p>"O God of my father Abraham, God of my father Isaac, LORD, who said to me, 'Go back to your country and your relatives, and I will make you prosper.'" Jacob's prayer is the most theologically developed prayer in Genesis. The triple divine address — God of Abraham + God of Isaac + YHWH — covers the full covenant-genealogy: personal covenant-history from grandfather to father to the covenant-name. Jacob grounds his petition in divine speech: "who said to me" — he is holding YHWH to his own word (31:3). Prayer that appeals to God's stated promise is covenant-prayer at its most confident.</p>""",
    "10": """<p>"I am unworthy of all the kindness and faithfulness (<em>ḥesed wĕʾĕmet</em>) you have shown your servant. I had only my staff when I crossed this Jordan, but now I have become two camps." The prayer's self-abasement is theologically precise: <em>qāṭōntî mikōl-haḥăsādîm</em> — "I am too small for all the loyal-loves" — the word <em>qāṭōn</em> (too small/insignificant) is a superlative self-diminishment. The covenant word-pair <em>ḥesed wĕʾĕmet</em> (loyal-love and faithfulness, also 24:27; 47:29) summarizes YHWH's character in covenant-relationship. "Only my staff (<em>bĕmaqlĕlî</em>)" — the single traveler's staff is the image of starting with nothing; "two camps" is the image of abundant covenant-blessing. The contrast measures YHWH's faithfulness.</p>""",
    "11": """<p>"Save me, I pray, from the hand of my brother Esau, for I am afraid he will come and attack me, and also the mothers with their children." The petition specifies the threat — not just Jacob personally but the mothers and children (i.e., the next generation of the covenant-family). The phrase "mothers with their children (<em>ʾēm ʿal-bānîm</em>)" is the most vulnerable element of the camp: attacking mothers with nursing children was the paradigm of military barbarism in the OT (2 Kgs 8:12; Hos 10:14; Amos 1:13). Jacob's prayer locates the covenant's continuity in the vulnerable children — the future of the promise depends on their survival.</p>""",
    "12": """<p>"But you have said, 'I will surely make you prosper and will make your descendants like the sand of the sea, which cannot be counted.'" The prayer closes with the covenant-promise as its ultimate ground. Jacob quotes YHWH's word (31:3: "I will be with you"; 28:14-15: the Bethel promise) back to YHWH — not as a demand but as a trust-anchor. The "sand of the sea" imagery for descendants is the Abrahamic covenant-vocabulary (22:17; 13:16). The appeal to YHWH's promise is the most powerful form of covenant-prayer: God's faithfulness to his own word is the basis of the petition, not Jacob's worthiness.</p>""",
    "13": """<p>"He spent the night there, and from what he had with him he selected a gift for his brother Esau." The night between prayer and action is structurally significant: Jacob prays (vv9-12) and then plans (vv13-21), not instead of praying but after praying. The gift-selection is a calculated appeasement strategy. In ANE diplomacy, a gift (minḥāh) sent ahead of a delegation was the standard method of softening a superior before a face-to-face meeting. The word <em>minḥāh</em> is also the word for "offering" — the gift to Esau uses the same vocabulary as a sacrificial offering, suggesting Jacob is treating the encounter with quasi-religious seriousness.</p>""",
    "14": """<p>Two hundred female goats and twenty male goats, two hundred ewes and twenty rams — the first installment of the gift inventory. The ratio of female-to-male (10:1) in each category maximizes reproductive value: female animals represent ongoing herd-building capacity, while males are the breeding stock. A gift structured for future productivity rather than mere present value shows sophisticated economic thinking. The totals are substantial: 220 goats, 220 sheep — portions of a large flock, not token gifts.</p>""",
    "15": """<p>Thirty female camels with their young, forty cows and ten bulls, twenty female donkeys and ten male donkeys — the second installment. The camels "with their young (<em>wĕyalḏêhen</em>)" are the most valuable single line: a nursing female camel with her young doubled the economic value of each animal. The selection of the most valuable animals in each category shows the scale of Jacob's appeasement investment. The total gift (vv14-15) would represent hundreds of animals — an enormous wealth-transfer by any ancient standard, designed to demonstrate that Jacob has not come to compete with Esau's resources.</p>""",
    "16": """<p>"He put them in the care of his servants, each herd by itself, and said to his servants, 'Go ahead of me, and keep some space between the herds.'" The spacing of the gift-herds is a psychological strategy: Esau will encounter gift after gift in waves, each wave building anticipation and softening reaction before Jacob himself appears. The "space between the herds (<em>rewah tāśîmû bên ʿēḏer ûḇên ʿēḏer</em>)" — both the word <em>rewah</em> (space/relief) and the spacing concept recall Rehoboth (26:22: "the LORD has made room for us"). The waves of gifts create expanding space between Esau's hostility and Jacob's approach.</p>""",
    "17": """<p>"When my brother Esau meets you and asks, 'Who do you belong to, and where are you going, and who owns all these animals in front of you?'" The scripted servant-reply anticipates Esau's interrogation of each gift-wave. The three questions Esau will ask — identity, destination, ownership — are the standard questions for a border-crossing challenge in the ANE. Jacob's pre-scripted answers ensure consistent messaging across all the gift-waves: each servant will give the same reply, reinforcing the narrative of a humble Jacob sending gifts to his master Esau.</p>""",
    "18": """<p>"They belong to your servant Jacob; they are a gift sent to my lord Esau, and he is coming behind us." The scripted reply repeats the servant/lord designation at least three times across vv18-20 — a deliberate reinforcement of Jacob's self-humbling posture. "He is coming behind us (<em>gam-hinnēh ʾaḥărênû</em>)" positions Jacob as following his gifts, not leading — the physical position of the suppliant before the patron. The sequential staging (gifts first, Jacob last) reverses the normal order of a dignitary's procession, where the principal comes first.</p>""",
    "19": """<p>"He also instructed the second, the third and all the others who followed the herds: 'You are to say the same thing to Esau when you meet him.'" The repeated scripting of each group of servants creates redundancy as a rhetorical strategy: five separate waves of gift-herds, each with its own servant giving the same rehearsed message, creates the cumulative effect of five separate encounters each saying the same thing. The ANE audience would recognize this as a classic diplomatic softening campaign — the repeated message, the repeated gifts, the repeated "your servant" designation all working in concert.</p>""",
    "20": """<p>"I will pacify him with these gifts I am sending on ahead; later, when I see him, perhaps he will receive me." The word "pacify" (<em>ʾăkappĕrāh pānāyw</em>) is the verb <em>kipper</em> — the same root as <em>kippûr</em>, the Day of Atonement. Jacob's diplomatic strategy uses atonement vocabulary: the gifts are meant to "cover/atone" Esau's face (his anger). "Perhaps (<em>ʾûlay</em>) he will receive me (<em>yiśśāʾ pānāy</em>)" — the phrase "lift up my face" is the idiom for acceptance and favor (the priestly blessing: "the LORD lift up his countenance upon you," Num 6:26). Jacob hopes Esau will "lift his face toward him" in acceptance rather than hostility.</p>""",
    "21": """<p>"So Jacob's gifts went on ahead of him, but he himself spent the night in the camp." The night Jacob spends in the camp after sending gifts and family ahead is the night of the wrestling match (vv22-31). The structural pattern is significant: Jacob has done everything humanly possible (prayer, military preparation, diplomatic gifts) and now faces the night alone. The stripping away of all human strategies and resources — gifts gone, family gone, alone at the ford — is the narrative's preparation for the divine encounter that transforms him.</p>""",
    "22": """<p>"That night Jacob got up and took his two wives, his two female servants and his eleven sons and crossed the ford of the Jabbok." The Jabbok river (modern Zarqa) is a significant Transjordanian boundary stream flowing westward into the Jordan. The name <em>Yabbōq</em> sounds like both <em>yaʿăqōḇ</em> (Jacob) and <em>yēʾāḇēq</em> (to wrestle) — a triple wordplay woven into the geography. The "ford (<em>maʿăḇar</em>)" was a shallow crossing point; the text specifies Jacob moved his entire household across before returning alone. The Jabbok crossing will become a type of the Jordan crossing into Canaan: both are water-boundary crossings that mark transformation.</p>""",
    "23": """<p>"After he had sent them across the stream, he sent over all his possessions." The progressive sending-across — family first, then possessions — leaves Jacob completely alone on the Jabbok's eastern bank. The reversal from the earlier military division (divide the camp for protection) to this complete exposure (send everyone across, stay alone) is stark: Jacob is now completely unprotected, having sent away his defense. The solitude is not carelessness but a deliberate positioning — or perhaps the narrative's irony: having arranged every human protection possible, Jacob is left alone for the one encounter no human strategy could arrange.</p>""",
    "24": """<p>"So Jacob was left alone, and a man wrestled with him till daybreak." "A man (<em>ʾîš</em>)" is the text's deliberately ambiguous identification of the wrestling figure. Jacob identifies the encounter as seeing God face to face (v30); Hosea 12:4 identifies the figure as "the angel" (<em>malʾāk</em>); the text says "a man." The ambiguity is the encounter's mystery: a divine figure who takes human form, like the three men at Mamre (ch18) and the man with the drawn sword before Joshua (Josh 5:13-15). The wrestling continues "until the breaking of the day (<em>ʿaḏ ʿălôt haššāḥar</em>)" — an all-night physical contest with a divine figure who does not reveal himself in the dark.</p>""",
    "25": """<p>"When the man saw that he could not overpower him, he touched the socket of Jacob's hip so that his hip was wrenched." The wrestling figure's inability to overpower Jacob — and the subsequent hip-touch — reveals the encounter's theological logic: the divine figure could end the match at will (as the hip-touch demonstrates: a single touch dislocates Jacob's hip) but chooses not to. The match continues at Jacob's persistence. The hip socket (<em>kap-yĕrēk</em>, the hollow of the thigh — the joint of the hip) is the same <em>yārēk</em> (thigh/loin) used in the oath-by-thigh custom (24:2; 47:29). The wrenching of the covenant-oath body-part is a bodily transformation.</p>""",
    "26": """<p>"Let me go, for it is daybreak. But Jacob replied, 'I will not let you go unless you bless me.'" The daybreak deadline — the divine figure asking to leave before dawn — may reflect the ANE convention that divine figures operate in the liminal spaces of night and that exposure to daylight ends the encounter's sacred ambiguity. Jacob's refusal to release without a blessing is the narrative's theological climax: the man who spent his life maneuvering for blessings (Esau's birthright, Isaac's blessing) now demands blessing directly from God himself. The demand is not presumptuous but persistent faith — grasping for the divine blessing the way he grasped Esau's heel at birth.</p>""",
    "27": """<p>"What is your name? 'Jacob,' he answered." The question of the name — coming from the divine figure — echoes Isaac's question in 27:18 ("Who are you, my son?"), where Jacob lied and said "Esau." The false identity claim obtained Isaac's blessing; the honest name-declaration here obtains the divine blessing. Jacob cannot receive the transforming blessing with a false name: he must come to God as he actually is — Jacob, the heel-grabber, the supplanter — before he can become Israel. The honest answer to "what is your name?" is the condition for the name-change that follows.</p>""",
    "28": """<p>"Your name will no longer be Jacob, but Israel, because you have struggled with God and with humans and have overcome." The name Israel (<em>yiśrāʾēl</em>) is explained via the etymology "he struggles with God (<em>śārāh ʾel</em>) and prevails (<em>yûkāl</em>)." The name change from Jacob (Heel-grabber, Supplanter — <em>yaʿăqōḇ</em>) to Israel (One-who-strives-with-God — <em>yiśrāʾēl</em>) is the covenant-family's founding moment: the man becomes the nation's name. "Struggled with God and with humans" encompasses Jacob's entire narrative arc: his wrestling with Esau, Laban, and YHWH are all instances of the same character-quality — persistent, tenacious engagement that refuses to let go without a blessing. The nation Israel inherits both the name and the character.</p>""",
    "29": """<p>"Please tell me your name. But he replied, 'Why do you ask my name?' Then he blessed him there." The divine figure's refusal to give his name follows the pattern of Manoah's inquiry of the angel (Judg 13:17-18: "why do you ask my name? It is beyond understanding"). In ANE thought, knowing a being's true name gave power over it — the divine refuses to be named and thereby controlled. The blessing without self-disclosure maintains the theological asymmetry: Jacob has wrestled with and been blessed by a being he cannot name or fully comprehend. The blessing itself is the gift; the name remains mystery.</p>""",
    "30": """<p>"It is because I saw God face to face, and yet my life was spared." The naming of Peniel/Penuel (<em>pĕnîʾēl</em>, face of God) interprets the encounter as a divine face-to-face meeting. The expectation that seeing God's face brings death (Exod 33:20: "you cannot see my face, for no one may see me and live") makes Jacob's survival the narrative's statement of extraordinary grace. "My life was spared (<em>wattinnāṣēl napšî</em>, my life was delivered)" — the verb <em>nāṣal</em> (to deliver/rescue) is the Exodus deliverance vocabulary. Encountering God is both the most dangerous and most life-giving thing that can happen — and Jacob has experienced both in one night.</p>""",
    "31": """<p>"The sun rose above him as he passed Peniel, and he was limping because of his hip." The sunrise marks the end of the liminal night-encounter and the beginning of the new day — Jacob/Israel's first sunrise. The limp (<em>ṣōlēaʿ</em>, limping) is the permanent physical mark of the night: Jacob has been changed bodily by the encounter. The limping patriarch approaching his brother with his hosts — wounded, walking unevenly, but carrying a new name — is the narrative's image of covenant-transformation: God's blessing does not always leave the recipient without marks. The limp is not a defeat but the cost of prevailing.</p>""",
    "32": """<p>"Therefore to this day the Israelites do not eat the tendon attached to the socket of the hip (<em>gîd hanāšeh</em>), because the socket of Jacob's hip was touched near the tendon." The <em>gîd hanāšeh</em> (sciatic nerve/hip tendon prohibition) is one of the oldest Jewish dietary laws, predating the Mosaic dietary code of Leviticus and Deuteronomy. The "to this day (<em>ʿaḏ hayyôm hazzeh</em>)" etiological formula grounds a known Jewish practice in the founding ancestor's experience. The prohibition preserves the memory of Jacob's encounter as a bodily practice: every time the sciatic nerve is removed from an animal (still required in kosher butchering), the act recalls the night at the Jabbok. The wound becomes communal memory through dietary law.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [31, 32]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    print(f'  Genesis context total: {len(result)} chapters, {after_count} verses')
    print('Genesis 31–32 mkt-context written.')

if __name__ == '__main__':
    main()
